# Dynamically generated by Terraform
export MODEL_BUCKET_PROD="stg-mlflow-models-mlops-zoomcamp-413093438819"
export PREDICTIONS_STREAM_NAME="stg_ride_predictions-mlops-zoomcamp"
export LAMBDA_FUNCTION="stg_ride_prediction_lambda_mlops-zoomcamp"

# Model artifacts bucket from previous weeks (experiment tracking)
export MODEL_BUCKET_DEV="mlflow-artifacts-remote433"

# Add profile and region to aws commands
: "${AWS_PROFILE:=default}"
: "${AWS_DEFAULT_REGION:=us-west-1}"

awsx() {
  aws --profile "$AWS_PROFILE" --region "$AWS_DEFAULT_REGION" "$@"
}

