# # 3. Extract the MLflow RUN_ID (32 hex chars)
# RUN_ID=$(echo "$LATEST_RUN_DIR" | grep -oE '[0-9a-f]{32}' | head -n 1)

RUN_ID=$(aws s3api list-objects-v2 --bucket "$MODEL_BUCKET_DEV" --query 'Contents[?contains(Key, `/artifacts/`)] | sort_by(@, &LastModified)[-1].Key' --output text \
  | sed -E 's|(.*)/artifacts/.*|\1|' | grep -oE '[0-9a-f]{32}' | head -1)

[[ -z "$RUN_ID" ]] && { echo "ERROR: No artifacts in ${MODEL_BUCKET_DEV}" >&2; exit 1; }

export RUN_ID
echo "Resolved RUN_ID:"
echo "  $RUN_ID"

# This is NOT FOR PRODUCTION
# Copy the model artifacts to the newly created production bucket
awsx s3 sync s3://${MODEL_BUCKET_DEV} s3://${MODEL_BUCKET_PROD}

# Set the environment variables for the Lambda function
# CRITICAL: TEST_RUN must be False or unset for Lambda to write predictions to Kinesis
# If TEST_RUN=True, callbacks will be empty and no records will be written
variables="{MODEL_BUCKET=${MODEL_BUCKET_PROD}, PREDICTIONS_STREAM_NAME=${PREDICTIONS_STREAM_NAME}, RUN_ID=${RUN_ID}, TEST_RUN=False}"

# Update the Lambda function (config only; does not update the Docker image/code)
awsx lambda update-function-configuration \
    --function-name ${LAMBDA_FUNCTION} \
    --environment "Variables=${variables}"
